--- a/priority_encoder.sv
+++ b/priority_encoder.sv
@@ -1,8 +1,8 @@
 module priority_encoder (
     input [7:0] request,
     input enable,
     output logic [2:0] priority_out
 );
-    always @(request) begin
+    always_comb begin
         if (request[7]) priority_out = 3'b111;
         else if (request[6]) priority_out = 3'b110;
         else if (request[5]) priority_out = 3'b101;
         else if (request[4]) priority_out = 3'b100;
         else if (request[3]) priority_out = 3'b011;
         else if (request[2]) priority_out = 3'b010;
         else if (request[1]) priority_out = 3'b001;
         else priority_out = 3'b000;
     end
 endmodule

